import{d,r as l,c as v,a as e,b as t,w as s,e as o,o as c,f as i,p as f,g as p,_ as b}from"./index-95246ce0.js";const r=n=>(f("data-v-b18149af"),n=n(),p(),n),g={class:"culture-detail-page"},u={class:"home-header"},_=r(()=>e("div",{class:"logo"},[e("h1",null,"山河桥语"),e("p",null,"中国古代桥梁时空数据可视化")],-1)),h={class:"nav-menu"},m=o('<main class="detail-content" data-v-b18149af><section class="detail-header" data-v-b18149af><h2 data-v-b18149af>洛阳桥</h2><p data-v-b18149af>中国古代第一座跨海梁式石桥</p></section><section class="detail-section" data-v-b18149af><div class="section-content" data-v-b18149af><h3 data-v-b18149af>基本信息</h3><div class="info-grid" data-v-b18149af><div class="info-item" data-v-b18149af><span class="info-label" data-v-b18149af>中文名</span><span class="info-value" data-v-b18149af>洛阳桥</span></div><div class="info-item" data-v-b18149af><span class="info-label" data-v-b18149af>别名</span><span class="info-value" data-v-b18149af>万安桥</span></div><div class="info-item" data-v-b18149af><span class="info-label" data-v-b18149af>地理位置</span><span class="info-value" data-v-b18149af>福建省泉州市洛江区万安街道</span></div><div class="info-item" data-v-b18149af><span class="info-label" data-v-b18149af>建造时间</span><span class="info-value" data-v-b18149af>北宋皇祐五年（1053年）</span></div><div class="info-item" data-v-b18149af><span class="info-label" data-v-b18149af>建成时间</span><span class="info-value" data-v-b18149af>北宋嘉祐四年（1059年）</span></div><div class="info-item" data-v-b18149af><span class="info-label" data-v-b18149af>桥梁类型</span><span class="info-value" data-v-b18149af>跨海梁式石桥</span></div><div class="info-item" data-v-b18149af><span class="info-label" data-v-b18149af>桥梁长度</span><span class="info-value" data-v-b18149af>834米</span></div><div class="info-item" data-v-b18149af><span class="info-label" data-v-b18149af>桥梁宽度</span><span class="info-value" data-v-b18149af>7米</span></div><div class="info-item" data-v-b18149af><span class="info-label" data-v-b18149af>桥墩数量</span><span class="info-value" data-v-b18149af>46个</span></div><div class="info-item" data-v-b18149af><span class="info-label" data-v-b18149af>保护级别</span><span class="info-value" data-v-b18149af>全国重点文物保护单位</span></div></div></div></section><section class="detail-section" data-v-b18149af><div class="section-content" data-v-b18149af><h3 data-v-b18149af>历史沿革</h3><p data-v-b18149af>洛阳桥始建于北宋皇祐五年（1053年），由泉州知州蔡襄主持建造，建成于北宋嘉祐四年（1059年）。</p><p data-v-b18149af>在历史上，洛阳桥经历了多次修缮：</p><ul data-v-b18149af><li data-v-b18149af><strong data-v-b18149af>南宋绍兴八年（1138年）</strong>：因台风损坏，进行了修缮。</li><li data-v-b18149af><strong data-v-b18149af>明宣德年间（1426-1435年）</strong>：进行了大规模的修缮。</li><li data-v-b18149af><strong data-v-b18149af>明万历三十五年（1607年）</strong>：因地震损坏，进行了修缮。</li><li data-v-b18149af><strong data-v-b18149af>清康熙二十八年（1689年）</strong>：进行了修缮。</li><li data-v-b18149af><strong data-v-b18149af>1932年</strong>：为了通行汽车，在洛阳桥旁边修建了一座钢筋混凝土桥。</li><li data-v-b18149af><strong data-v-b18149af>1993-1996年</strong>：对洛阳桥进行了全面的修缮，恢复了其历史原貌。</li></ul></div></section><section class="detail-section" data-v-b18149af><div class="section-content" data-v-b18149af><h3 data-v-b18149af>建筑特色</h3><p data-v-b18149af>洛阳桥是中国古代第一座跨海梁式石桥，其建筑特色主要体现在以下几个方面：</p><h4 data-v-b18149af>1. 筏形基础</h4><p data-v-b18149af>洛阳桥采用了筏形基础，即在水中抛填石块，形成一条横跨江底的矮石堤，然后在石堤上建造桥墩。这种基础形式有效地解决了在松软地基上建造桥梁的问题。</p><h4 data-v-b18149af>2. 种蛎固基法</h4><p data-v-b18149af>洛阳桥采用了种蛎固基法，即在桥墩周围养殖牡蛎，利用牡蛎的贝壳将石块胶结在一起，增强桥墩的稳定性。这种方法是中国古代桥梁建筑的重要创新。</p><h4 data-v-b18149af>3. 浮运架梁法</h4><p data-v-b18149af>洛阳桥采用了浮运架梁法，即将巨大的石梁放在船上，利用涨潮时的浮力将石梁运到桥墩上。这种方法解决了在宽阔的江面上架设巨大石梁的问题。</p><h4 data-v-b18149af>4. 尖劈桥墩</h4><p data-v-b18149af>洛阳桥的桥墩设计成尖劈形，这种设计可以减少水流对桥墩的冲击力，增强桥梁的稳定性。</p></div></section><section class="detail-section" data-v-b18149af><div class="section-content" data-v-b18149af><h3 data-v-b18149af>历史意义</h3><p data-v-b18149af>洛阳桥在中国桥梁史上具有重要的历史意义：</p><ul data-v-b18149af><li data-v-b18149af>它是中国古代第一座跨海梁式石桥，体现了中国古代桥梁建筑的高超技艺。</li><li data-v-b18149af>它采用的筏形基础、种蛎固基法等技术，是中国古代桥梁建筑的重要创新，对后世桥梁建设产生了深远影响。</li><li data-v-b18149af>它是泉州海上丝绸之路的重要组成部分，见证了泉州作为海上丝绸之路起点的繁荣。</li><li data-v-b18149af>它是中国古代科技成就的重要代表，被列为全国重点文物保护单位。</li></ul></div></section><section class="detail-section" data-v-b18149af><div class="section-content" data-v-b18149af><h3 data-v-b18149af>文化内涵</h3><p data-v-b18149af>洛阳桥不仅是一座实用的交通设施，也是中国传统文化的重要象征：</p><h4 data-v-b18149af>1. 蔡襄与洛阳桥</h4><p data-v-b18149af>洛阳桥的建造与北宋名臣蔡襄密切相关。蔡襄时任泉州知州，他亲自规划、设计和监督了洛阳桥的建造，为桥梁的成功建造做出了重要贡献。</p><h4 data-v-b18149af>2. 碑刻与题字</h4><p data-v-b18149af>洛阳桥上保存有许多碑刻和题字，其中最著名的是蔡襄撰写的《万安桥记》碑，记载了洛阳桥的建造过程和历史意义。</p><h4 data-v-b18149af>3. 民俗活动</h4><p data-v-b18149af>每年的农历三月初三，洛阳桥周边会举行盛大的民俗活动，如踩桥、祈愿等，体现了当地人民对洛阳桥的敬仰和崇拜。</p></div></section><section class="detail-section" data-v-b18149af><div class="section-content" data-v-b18149af><h3 data-v-b18149af>桥梁图片</h3><div class="image-gallery" data-v-b18149af><img src="https://trae-api-cn.mchost.guru/api/ide/v1/text_to_image?prompt=Luoyang%20Bridge%20ancient%20stone%20bridge%20in%20Quanzhou%2C%20Fujian%2C%20Song%20Dynasty%2C%20historical%20landmark%2C%20full%20view&amp;image_size=landscape_16_9" alt="洛阳桥全景" class="gallery-image" data-v-b18149af><img src="https://trae-api-cn.mchost.guru/api/ide/v1/text_to_image?prompt=Luoyang%20Bridge%20piers%20close%20up%2C%20ancient%20Chinese%20bridge%2C%20stone%20structure&amp;image_size=landscape_16_9" alt="洛阳桥桥墩" class="gallery-image" data-v-b18149af><img src="https://trae-api-cn.mchost.guru/api/ide/v1/text_to_image?prompt=Luoyang%20Bridge%20碑刻%2C%20ancient%20Chinese%20bridge%2C%20historical%20inscriptions&amp;image_size=landscape_16_9" alt="洛阳桥碑刻" class="gallery-image" data-v-b18149af></div></div></section></main><footer class="page-footer" data-v-b18149af><p data-v-b18149af>© 2026 山河桥语 - 中国古代桥梁时空数据可视化</p></footer>',2),y=d({__name:"BridgeLuoyangPage",setup(n){return(C,x)=>{const a=l("router-link");return c(),v("div",g,[e("header",u,[_,e("nav",h,[t(a,{to:"/",class:"nav-item"},{default:s(()=>[i("首页")]),_:1}),t(a,{to:"/visualization",class:"nav-item"},{default:s(()=>[i("数据可视化")]),_:1}),t(a,{to:"/culture",class:"nav-item active"},{default:s(()=>[i("文化介绍")]),_:1}),t(a,{to:"/statistics",class:"nav-item"},{default:s(()=>[i("数据统计")]),_:1}),t(a,{to:"/about",class:"nav-item"},{default:s(()=>[i("关于项目")]),_:1})])]),m])}}});const L=b(y,[["__scopeId","data-v-b18149af"]]);export{L as default};
